pan&gt; &lt;span class=&#34;title&#34;&gt;multiple&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;keys&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;to&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;multiple&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;values&lt;/span&gt;, &lt;span class=&#34;title&#34;&gt;only&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;none&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;keys&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;exist&lt;/span&gt;（将多个键设置为多个值，仅当这些键不存在时才设置）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.0.1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;PSETEX&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;milliseconds&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Set&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;and&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;expiration&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;milliseconds&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;（置键的值和到期时间(以毫秒为单位)）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.6.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;SET&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; [&lt;span class=&#34;title&#34;&gt;expiration&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;EX&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;seconds&lt;/span&gt;|&lt;span class=&#34;title&#34;&gt;PX&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;milliseconds&lt;/span&gt;] [&lt;span class=&#34;title&#34;&gt;NX&lt;/span&gt;|&lt;span class=&#34;title&#34;&gt;XX&lt;/span&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Set&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;string&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;（设置键的字符串值）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.0.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;SETBIT&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;offset&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Sets&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;or&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;clears&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;bit&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;at&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;offset&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;string&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;stored&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;at&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;（设置或清除存储在键上的字符串值中的偏移位）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.2.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;SETEX&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;seconds&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Set&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;and&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;expiration&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;（设置键的值和过期时间）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.0.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;SETNX&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Set&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;, &lt;span class=&#34;title&#34;&gt;only&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;does&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;not&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;exist&lt;/span&gt;（设置键值，仅当键不存在时才设置）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.0.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;SETRANGE&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;offset&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Overwrite&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;part&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;string&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;at&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;starting&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;at&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;specified&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;offset&lt;/span&gt;（覆盖从指定偏移量开始的键处的字符串部分）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.2.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;STRLEN&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Get&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;length&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;stored&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;（获取存储在键中的值的长度）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt; &lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.2.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
