&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;set&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;within&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;given&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;scores&lt;/span&gt;(删除给定分数内排序集合中的所有成员)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.2.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;ZREVRANGE&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;start&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;stop&lt;/span&gt; [&lt;span class=&#34;title&#34;&gt;WITHSCORES&lt;/span&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Return&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;range&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;members&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;set&lt;/span&gt;, &lt;span class=&#34;title&#34;&gt;by&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;index&lt;/span&gt;, &lt;span class=&#34;title&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;scores&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;ordered&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;from&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;high&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;to&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;low&lt;/span&gt;(按索引返回排序集合中成员的范围，分数从高到低排序)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.2.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;ZREVRANGEBYLEX&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;max&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;min&lt;/span&gt; [&lt;span class=&#34;title&#34;&gt;LIMIT&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;offset&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;count&lt;/span&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Return&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;range&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;members&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;set&lt;/span&gt;, &lt;span class=&#34;title&#34;&gt;by&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;lexicographical&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;range&lt;/span&gt;, &lt;span class=&#34;title&#34;&gt;ordered&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;from&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;higher&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;to&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;lower&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;strings&lt;/span&gt;.(按字典顺序从较高的字符串到较低的字符串，返回已排序集合中成员的范围。)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.8.9&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;ZREVRANGEBYSCORE&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;max&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;min&lt;/span&gt; [&lt;span class=&#34;title&#34;&gt;WITHSCORES&lt;/span&gt;] [&lt;span class=&#34;title&#34;&gt;LIMIT&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;offset&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;count&lt;/span&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Return&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;range&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;members&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;set&lt;/span&gt;, &lt;span class=&#34;title&#34;&gt;by&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;score&lt;/span&gt;, &lt;span class=&#34;title&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;scores&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;ordered&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;from&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;high&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;to&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;low&lt;/span&gt;(按分数返回排序集中的成员范围，分数从高到低排序)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.2.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;ZREVRANK&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;member&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Determine&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;index&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;member&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;set&lt;/span&gt;, &lt;span class=&#34;title&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;scores&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;ordered&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;from&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;high&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;to&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;low&lt;/span&gt;(根据分数从高到低的顺序，确定排序集合中成员的索引)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.0.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;ZSCAN&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;cursor&lt;/span&gt; [&lt;span class=&#34;title&#34;&gt;MATCH&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;pattern&lt;/span&gt;] [&lt;span class=&#34;title&#34;&gt;COUNT&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;count&lt;/span&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Incrementally&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;iterate&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sets&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;elements&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;and&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;associated&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;scores&lt;/span&gt;(增量迭代已排序的集合元素和相关分数)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.8.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;ZSCORE&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;member&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Get&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;score&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;associated&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;with&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;given&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;member&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;set&lt;/span&gt;(获取排序集中与给定成员关联的分数)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.2.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;ZUNIONSTORE&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;destination&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;numkeys&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; [&lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; ...] [&lt;span class=&#34;title&#34;&gt;WEIGHTS&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;weight&lt;/span&gt;] [&lt;span class=&#34;title&#34;&gt;AGGREGATE&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;SUM&lt;/span&gt;|&lt;span class=&#34;title&#34;&gt;MIN&lt;/span&gt;|&lt;span class=&#34;title&#34;&gt;MAX&lt;/span&gt;]&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Add&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;multiple&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sets&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;and&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;store&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;resulting&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;sorted&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;set&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt;(添加多个排序集，并将结果排序集存储到一个新键中)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 2.0.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;使用场景&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;code&gt;ZSet&lt;/code&gt;  集合操作实现排行榜&lt;/li&gt;
&lt;/ol&gt;

 &lt;p&gt;MyBatis 源码阅读环境编译，能够更方便阅读源码，可以切换源码版本！&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
